24: type sessionIssuerHelper struct {
25: 	*extsvc.CodeHost
26: 	logger      log.Logger
27: 	clientID    string
28: 	db          database.DB
29: 	allowSignup *bool
30: 	allowGroups []string
31: 	scopes      []string
32: }
33: 
34: func (s *sessionIssuerHelper) AuthAuditEntity() string {
35: 	return "auth.gitlab"
36: }
37: 
38: func (s *sessionIssuerHelper) GetServiceID() string {
39: 	return s.ServiceID
40: }
