46: func (s *sessionIssuerHelper) ExtractValidationIdentity(ctx context.Context, token *oauth2.Token) (*oauth.ValidationIdentityInfo, error) {
47: 	ctx, err := s.populateUserContext(ctx, token)
48: 	if err != nil {
49: 		return nil, err
50: 	}
51: 
52: 	info := &oauth.ValidationIdentityInfo{}
53: 	user, err := UserFromContext(ctx)
54: 	if err != nil {
55: 		return nil, err
56: 	}
57: 
58: 	info.Subject = strconv.FormatInt(int64(user.ID), 10)
59: 	info.Email = user.Email
60: 	info.Username = user.Username
61: 	info.DisplayName = user.Name
62: 
63: 	if info.Email == "" {
64: 		info.Warnings = append(info.Warnings, "No email returned for this GitLab account")
65: 	}
66: 
67: 	provider := gitlab.NewClientProvider(extsvc.URNGitLabOAuth, s.BaseURL, nil)
68: 	glClient := provider.GetOAuthClient(token.AccessToken)
69: 	userBelongsToAllowedGroups, err := s.verifyUserGroups(ctx, glClient)
70: 	if err != nil {
71: 		return nil, err
72: 	}
73: 	if !userBelongsToAllowedGroups {
74: 		info.Warnings = append(info.Warnings, "User does not belong to any of the configured allowed GitLab groups")
75: 	}
76: 
77: 	return info, nil
78: }
79: 
80: func (s *sessionIssuerHelper) GetOrCreateUser(ctx context.Context, token *oauth2.Token) (result *oauth.SessionIssuerHelperResult, safeErrMsg string, err error) {
81: 	ctx, err = s.populateUserContext(ctx, token)
82: 	if err != nil {
83: 		return nil, "Could not read GitLab user from callback request.", err
84: 	}
85: 
86: 	gUser, err := UserFromContext(ctx)
87: 	if err != nil {
88: 		return nil, "Could not read GitLab user from callback request.", errors.Wrap(err, "could not read user from context")
89: 	}
90: 
91: 	provider := gitlab.NewClientProvider(extsvc.URNGitLabOAuth, s.BaseURL, nil)
92: 	glClient := provider.GetOAuthClient(token.AccessToken)
93: 
94: 	// 🚨 SECURITY: Ensure that the user is part of one of the allowed groups or subgroups when the allowGroups option is set.
95: 	userBelongsToAllowedGroups, err := s.verifyUserGroups(ctx, glClient)
96: 	if err != nil {
97: 		message := "Error verifying user groups."
98: 		return nil, message, err
99: 	}
100: 
101: 	if !userBelongsToAllowedGroups {
102: 		message := "User does not belong to allowed GitLab groups or subgroups."
103: 		return nil, message, errors.New(message)
104: 	}
105: 
106: 	// AllowSignup defaults to true when not set to preserve the existing behavior.
107: 	signupAllowed := s.allowSignup == nil || *s.allowSignup
108: 
109: 	var data extsvc.AccountData
110: 	if err := gitlab.SetExternalAccountData(&data, gUser, token, s.scopes); err != nil {
111: 		return nil, "", err
112: 	}
113: 
114: 	recorder := telemetryrecorder.New(s.db)
115: 
116: 	// Unlike with GitHub, we can *only* use the primary email to resolve the user's identity,
117: 	// because the GitLab API does not return whether an email has been verified. The user's primary
118: 	// email on GitLab is always verified, so we use that.
119: 	authResult, safeErrMsg, err := auth.GetAndSaveUser(ctx, s.logger, s.db, recorder, auth.GetAndSaveUserOp{
120: 		UserProps: database.NewUser{
121: 			Username:        gUser.Username,
122: 			Email:           gUser.Email,
123: 			EmailIsVerified: gUser.Email != "",
124: 			DisplayName:     gUser.Name,
125: 			AvatarURL:       gUser.AvatarURL,
126: 		},
127: 		ExternalAccount: extsvc.AccountSpec{
128: 			ServiceType: s.ServiceType,
129: 			ServiceID:   s.ServiceID,
130: 			ClientID:    s.clientID,
131: 			AccountID:   strconv.FormatInt(int64(gUser.ID), 10),
132: 		},
133: 		ExternalAccountData: data,
134: 		CreateIfNotExist:    signupAllowed,
135: 	})
136: 	if err != nil {
137: 		return nil, safeErrMsg, err
138: 	}
139: 
140: 	return &oauth.SessionIssuerHelperResult{
141: 		NewUserCreated:    authResult.NewUserCreated,
142: 		Actor:             actor.FromUser(authResult.UserID),
143: 		ExternalAccountID: authResult.ExternalAccountID,
144: 	}, "", nil
145: }
