151: func (s *sessionIssuerHelper) SessionData(token *oauth2.Token) oauth.SessionData {
152: 	return oauth.SessionData{
153: 		ID: providers.ConfigID{
154: 			ID:   s.ServiceID,
155: 			Type: s.ServiceType,
156: 		},
157: 		AccessToken: token.AccessToken,
158: 		TokenType:   token.Type(),
159: 		// TODO(beyang): store and use refresh token to auto-refresh sessions
160: 	}
161: }
