163: func (s *sessionIssuerHelper) populateUserContext(ctx context.Context, token *oauth2.Token) (context.Context, error) {
164: 	if _, err := UserFromContext(ctx); err == nil {
165: 		return ctx, nil
166: 	}
167: 
168: 	provider := gitlab.NewClientProvider(extsvc.URNGitLabOAuth, s.BaseURL, nil)
169: 	glClient := provider.GetOAuthClient(token.AccessToken)
170: 	user, err := glClient.GetUser(ctx, "")
171: 	if err != nil {
172: 		return ctx, errors.Wrap(err, "unable to get GitLab user")
173: 	}
174: 	if user == nil || user.ID == 0 {
175: 		return ctx, errors.New("unable to get GitLab user: bad user info")
176: 	}
177: 	return WithUser(ctx, user), nil
178: }
179: 
180: // verifyUserGroups checks whether the authenticated user belongs to one of the GitLab groups when the allowGroups option is set.
181: func (s *sessionIssuerHelper) verifyUserGroups(ctx context.Context, glClient *gitlab.Client) (bool, error) {
182: 	if len(s.allowGroups) == 0 {
183: 		return true, nil
184: 	}
185: 
186: 	user, err := UserFromContext(ctx)
187: 	if err != nil {
188: 		return false, err
189: 	}
190: 
191: 	for _, group := range s.allowGroups {
192: 		isMember, err := glClient.IsGroupMember(ctx, group, user.ID)
193: 		if err != nil {
194: 			return false, err
195: 		}
196: 		if isMember {
197: 			return true, nil
198: 		}
199: 	}
200: 
201: 	return false, nil
202: }
