2: 
3: import (
4: 	"context"
5: 	"fmt"
6: 	"net/http"
7: 	"net/url"
8: 	"strconv"
9: 	"strings"
10: 
11: 	"github.com/sourcegraph/sourcegraph/internal/extsvc/gitlab/gql"
12: 	"github.com/sourcegraph/sourcegraph/lib/collections"
