16: type Group struct {
17: 	ID          int32  `json:"id"`
18: 	Name        string `json:"name"`
19: 	FullPath    string `json:"full_path"`
20: 	Description string `json:"description"`
21: 	WebURL      string `json:"web_url"`
22: 	AvatarURL   string `json:"avatar_url"`
23: 	Visibility  string `json:"visibility"`
24: }
25: 
26: var (
27: 	MockIsGroupMember  func(ctx context.Context, groupPath string, userID int32) (bool, error)
28: 	MockGetGroupsByIDs func(c *Client, ctx context.Context, ids []string) ([]*Group, error)
29: )
30: 
31: // IsGroupMember checks whether a user is a member of a GitLab group (including inherited membership)
32: func (c *Client) IsGroupMember(ctx context.Context, groupPath string, userID int32) (bool, error) {
33: 	if MockIsGroupMember != nil {
34: 		return MockIsGroupMember(ctx, groupPath, userID)
35: 	}
36: 
37: 	u := fmt.Sprintf("groups/%s/members/all/%d", url.PathEscape(groupPath), userID)
38: 	req, err := http.NewRequestWithContext(ctx, "GET", u, nil)
39: 	if err != nil {
40: 		return false, err
41: 	}
42: 
43: 	var member struct{}
44: 	_, _, err = c.do(ctx, req, &member)
45: 	if err != nil {
46: 		if IsNotFound(err) {
47: 			return false, nil
48: 		}
49: 		return false, err
50: 	}
51: 
52: 	return true, nil
53: }
54: 
55: // ListTopLevelUserGroups lists the top-most groups that the current authenticated user is a member of.
56: // If a user is only a member of a sub-group, this method will return the top-most group that contains that sub-group.
57: // It supports search, pagination, and returns total count for UI purposes.
58: //
59: // Note: When calling subsequent pages, call the same method with the same arguments, just
60: // with the previous "after" value. (Any changes to the other arguments like "limit" will result in undefined behavior.)
61: func (c *Client) ListTopLevelUserGroups(ctx context.Context, search string, limit int, after string) ([]*Group, int, string, error) {
62: 	if MockListTopLevelUserGroups != nil {
63: 		return MockListTopLevelUserGroups(c, ctx, search, limit, after)
64: 	}
65: 
66: 	if limit <= 0 || limit > 100 {
67: 		return nil, 0, "", errors.New("limit must be between 1 and 100")
68: 	}
69: 
70: 	graphqlClient := c.mkGraphQLClient()
71: 	response, err := graphqlClient.GetTopLevelUserGroups(ctx, limit, after, search)
72: 	if err != nil {
73: 		return nil, 0, "", errors.Wrap(err, "failed to fetch user groups via GraphQL")
74: 	}
75: 
76: 	groupsConnection := response.GetGroups()
77: 	nodes := groupsConnection.GetNodes()
78: 
79: 	groups := make([]*Group, 0, len(nodes))
80: 	for _, gqlGroup := range nodes {
81: 		group, err := convertGraphQLGroupToGroup(&gqlGroup)
82: 		if err != nil {
83: 			return nil, 0, "", errors.Wrapf(err, "failed to convert GraphQL group %s", gqlGroup.GetId())
84: 		}
85: 		groups = append(groups, group)
86: 	}
87: 
88: 	totalCount := groupsConnection.GetCount()
89: 	pageInfo := groupsConnection.GetPageInfo()
90: 
91: 	nextCursor := ""
92: 	if pageInfo.GetHasNextPage() {
93: 		nextCursor = pageInfo.GetEndCursor()
94: 	}
95: 
96: 	return groups, totalCount, nextCursor, nil
97: }
98: 
99: // GetGroup retrieves detailed information about a specific group.
100: func (c *Client) GetGroup(ctx context.Context, id int) (*Group, error) {
101: 	if MockGetGroup != nil {
102: 		return MockGetGroup(c, ctx, id)
103: 	}
104: 
105: 	req, err := http.NewRequestWithContext(ctx, "GET", fmt.Sprintf("groups/%d", id), nil)
106: 	if err != nil {
107: 		return nil, err
108: 	}
109: 
110: 	var group Group
111: 	_, _, err = c.do(ctx, req, &group)
112: 	if err != nil {
113: 		return nil, err
114: 	}
115: 
116: 	return &group, nil
117: }
118: 
119: // GetGroupsByIDs retrieves multiple groups by their IDs using the GitLab GraphQL API.
120: // This method supports batch fetching up to 50 groups at a time to align with GitLab API limits.
121: // Group IDs should be provided as GraphQL Global IDs (e.g., "gid://gitlab/Group/1234") or
122: // numeric strings that will be converted to GraphQL Global IDs automatically.
123: //
124: // The method handles internal pagination transparently - if GitLab paginates the response,
125: // this method will make additional requests to fetch all requested groups.
126: //
127: // Returns:
128: //   - groups: slice of Group objects for the requested IDs
129: //   - error: any error encountered during the API call
130: //
131: // Example usage:
132: //
133: //	groups, err := client.GetGroupsByIDs(ctx, []string{"gid://gitlab/Group/1234", "5678"})
134: func (c *Client) GetGroupsByIDs(ctx context.Context, ids []string) ([]*Group, error) {
135: 	if MockGetGroupsByIDs != nil {
136: 		return MockGetGroupsByIDs(c, ctx, ids)
137: 	}
138: 
139: 	if len(ids) == 0 {
140: 		return []*Group{}, nil
141: 	}
142: 
143: 	if len(ids) > 50 {
144: 		return nil, errors.New("cannot fetch more than 50 groups at once")
145: 	}
146: 
147: 	// Convert numeric IDs to GraphQL Global IDs if needed
148: 	gqlIDs := make([]string, len(ids))
149: 	for i, id := range ids {
150: 		if isNumericID(id) {
151: 			gqlIDs[i] = fmt.Sprintf("gid://gitlab/Group/%s", id)
152: 		} else {
153: 			gqlIDs[i] = id
154: 		}
155: 	}
156: 
157: 	deduplicatedIDs := collections.Deduplicate(gqlIDs)
158: 
159: 	graphqlClient := c.mkGraphQLClient()
160: 	allGroups := make([]*Group, 0, len(deduplicatedIDs))
161: 	cursor := ""
162: 
163: 	for {
164: 		// Request a reasonable page size to avoid too many API calls
165: 		// Since we're limited to 50 total groups, use 50 as first value
166: 		response, err := graphqlClient.GetGroupsByIDs(ctx, deduplicatedIDs, 50, cursor)
167: 		if err != nil {
168: 			return nil, errors.Wrap(err, "failed to fetch groups via GraphQL")
169: 		}
170: 
171: 		groups := response.GetGroups()
172: 		nodes := groups.GetNodes()
173: 
174: 		// Convert and append this page of groups
175: 		for _, gqlGroup := range nodes {
176: 			group, err := convertGraphQLGroupToGroup(&gqlGroup)
177: 			if err != nil {
178: 				return nil, errors.Wrapf(err, "failed to convert GraphQL group %s", gqlGroup.GetId())
179: 			}
180: 			allGroups = append(allGroups, group)
181: 		}
182: 
183: 		// Check if there are more pages
184: 		pageInfo := groups.GetPageInfo()
185: 		if !pageInfo.GetHasNextPage() {
186: 			break
187: 		}
188: 
189: 		cursor = pageInfo.GetEndCursor()
190: 		if cursor == "" {
191: 			break // Safety check to prevent infinite loops
192: 		}
193: 	}
194: 
195: 	return allGroups, nil
196: }
197: 
198: // isNumericID checks if the provided ID is numeric (and thus needs to be converted to a GraphQL Global ID)
199: func isNumericID(id string) bool {
200: 	_, err := strconv.Atoi(id)
201: 	return err == nil
202: }
203: 
204: // convertGraphQLGroupToGroup converts a GraphQL Group object to a REST API Group struct
205: func convertGraphQLGroupToGroup(gqlGroup *gql.GroupConnectionFieldsNodesGroup) (*Group, error) {
206: 	if gqlGroup == nil {
207: 		return nil, errors.New("GraphQL group cannot be nil")
208: 	}
209: 
210: 	// Parse the numeric ID from the GraphQL Global ID
211: 	id, err := parseGraphQLGroupID(gqlGroup.GetId())
212: 	if err != nil {
213: 		return nil, errors.Wrap(err, "failed to parse group ID")
214: 	}
215: 
216: 	return &Group{
217: 		ID:          int32(id),
218: 		Name:        gqlGroup.GetName(),
219: 		FullPath:    gqlGroup.GetFullPath(),
220: 		Description: gqlGroup.GetDescription(),
221: 		WebURL:      gqlGroup.GetWebUrl(),
222: 		AvatarURL:   gqlGroup.GetAvatarUrl(),
223: 		Visibility:  gqlGroup.GetVisibility(),
224: 	}, nil
225: }
226: 
227: // parseGraphQLGroupID parses the string ID to int for compatibility with REST API
228: // TODO@ggilmore: This is a footgun. The GraphQL API returns the ID as a string that looks like gid://gitlab/Group/108329154,
229: // but the REST API returns the ID as an int like 108329154.
230: //
231: // We need to figure out how to reconcile this.
232: func parseGraphQLGroupID(id string) (int, error) {
233: 	const prefix = "gid://gitlab/Group/"
234: 	if !strings.HasPrefix(id, prefix) {
235: 		return 0, errors.New("GraphQL group ID is not a valid group ID")
236: 	}
237: 	idStr := strings.TrimPrefix(id, prefix)
238: 	return strconv.Atoi(idStr)
239: }
