3: import (
4: 	"net/http"
5: 	"net/url"
6: 
7: 	"github.com/dghubble/gologin/v2"
8: 	oauth2Login "github.com/dghubble/gologin/v2/oauth2"
9: 	"golang.org/x/oauth2"
10: 
11: 	"github.com/sourcegraph/log"
12: 
13: 	"github.com/sourcegraph/sourcegraph/internal/extsvc"
14: 	"github.com/sourcegraph/sourcegraph/internal/extsvc/gitlab"
15: 	"github.com/sourcegraph/sourcegraph/lib/errors"
16: )
