18: // SSOLoginHandler is a custom implementation of github.com/dghubble/gologin/oauth2's LoginHandler method.
19: // It takes an extra ssoAuthURL parameter, and adds the original authURL as a redirect parameter to that
20: // URL.
21: //
22: // This is used in cases where customers use SAML/SSO on their GitLab configurations. The default
23: // way GitLab handles redirects for groups that require SSO sign-on does not work, and users
24: // need to sign into GitLab outside of Sourcegraph, and can only then come back and use OAuth.
25: //
26: // This implementaion allows users to be directed to their GitLab SSO sign-in page, and then
27: // the redirect query parameter will redirect them to the OAuth sign-in flow that Sourcegraph
28: // requires.
29: func SSOLoginHandler(config *oauth2.Config, failure http.Handler, ssoAuthURL string) http.Handler {
30: 	if failure == nil {
31: 		failure = gologin.DefaultFailureHandler
32: 	}
33: 	fn := func(w http.ResponseWriter, req *http.Request) {
34: 		ctx := req.Context()
35: 		state, err := oauth2Login.StateFromContext(ctx)
36: 		if err != nil {
37: 			ctx = gologin.WithError(ctx, err)
38: 			failure.ServeHTTP(w, req.WithContext(ctx))
39: 			return
40: 		}
41: 		authURL, err := url.Parse(config.AuthCodeURL(state))
42: 		if err != nil {
43: 			ctx = gologin.WithError(ctx, err)
44: 			failure.ServeHTTP(w, req.WithContext(ctx))
45: 			return
46: 		}
47: 
48: 		ssoAuthURL, err := url.Parse(ssoAuthURL)
49: 		if err != nil {
50: 			ctx = gologin.WithError(ctx, err)
51: 			failure.ServeHTTP(w, req.WithContext(ctx))
52: 			return
53: 		}
54: 		queryParams := ssoAuthURL.Query()
55: 		queryParams.Add("redirect", authURL.Path+"?"+authURL.RawQuery)
56: 		ssoAuthURL.RawQuery = queryParams.Encode()
57: 		http.Redirect(w, req, ssoAuthURL.String(), http.StatusFound)
58: 	}
59: 	return http.HandlerFunc(fn)
60: }
61: 
62: func LoginHandler(config *oauth2.Config, failure http.Handler) http.Handler {
63: 	return oauth2Login.LoginHandler(config, failure)
64: }
65: 
66: func CallbackHandler(config *oauth2.Config, success, failure http.Handler) http.Handler {
67: 	success = gitlabHandler(config, success, failure)
68: 	return oauth2Login.CallbackHandler(config, success, failure)
69: }
70: 
71: func gitlabHandler(config *oauth2.Config, success, failure http.Handler) http.Handler {
72: 	logger := log.Scoped("GitlabOAuthHandler")
73: 
74: 	if failure == nil {
75: 		failure = gologin.DefaultFailureHandler
76: 	}
77: 	fn := func(w http.ResponseWriter, req *http.Request) {
78: 		ctx := req.Context()
79: 		token, err := oauth2Login.TokenFromContext(ctx)
80: 		if err != nil {
81: 			ctx = gologin.WithError(ctx, err)
82: 			failure.ServeHTTP(w, req.WithContext(ctx))
83: 			return
84: 		}
85: 
86: 		gitlabClient, err := gitlabClientFromAuthURL(config.Endpoint.AuthURL, token.AccessToken)
87: 		if err != nil {
88: 			ctx = gologin.WithError(ctx, errors.Errorf("could not parse AuthURL %s", config.Endpoint.AuthURL))
89: 			failure.ServeHTTP(w, req.WithContext(ctx))
90: 			return
91: 		}
92: 		user, err := gitlabClient.GetUser(ctx, "")
