	"github.com/sourcegraph/sourcegraph/internal/licensing"
	"github.com/sourcegraph/sourcegraph/schema"
)

const authPrefix = auth.AuthURLPrefix + "/gitlab"

func Init(logger log.Logger, db database.DB, gp gating.Provider) {
	const pkgName = "gitlaboauth"
	logger = log.Scoped(pkgName)

	conf.ContributeValidator(func(ctx context.Context, cfg conftypes.SiteConfigQuerier) conftypes.Problems {
		_, problems := parseConfig(ctx, logger, gp, cfg, db)
		return problems
	})

	providers.RegisterProviderFactory(func(ctx context.Context, cfg conftypes.SiteConfigQuerier) []providers.Provider {
		checkErr := gp.Check(ctx, licensing.FeatureSSO)
		if checkErr != nil {
			return nil
		}

		newProviders, _ := parseConfig(ctx, logger, gp, cfg, db)
		if len(newProviders) == 0 {
			return nil
		}

		newProvidersList := make([]providers.Provider, 0, len(newProviders))
		for _, p := range newProviders {
			newProvidersList = append(newProvidersList, p.Provider)
		}

		return newProvidersList
	})
}

type Provider struct {
	*schema.GitLabAuthProvider
	providers.Provider
}

func parseConfig(ctx context.Context, logger log.Logger, gp gating.Provider, cfg conftypes.SiteConfigQuerier, db database.DB) (ps []Provider, problems conftypes.Problems) {
	existingProviders := make(collections.Set[string])
	for _, pr := range cfg.SiteConfig().AuthProviders {
		if pr.Gitlab == nil {
			continue
		}

		extURL, err := db.Conf().GetExternalURL(ctx)
		if err != nil {
			if errors.Is(err, tenant.ErrNoExternalURL) {
				problems = append(problems, conftypes.NewSiteProblem("`externalURL` was empty and it is needed to determine the OAuth callback URL."))
			} else {
				problems = append(problems, conftypes.NewSiteProblem(fmt.Sprintf("error getting Sourcegraph external URL: %v", err)))
			}
			continue
		}
		callbackURL := *extURL
		callbackURL.Path = "/.auth/gitlab/callback"

		provider := parseProvider(logger, gp, db, callbackURL.String(), pr.Gitlab, pr)
		if provider == nil {
			continue
		}

		ci := provider.CachedInfo(ctx)
		uniqueID := ci.UniqueID()

		if existingProviders.Has(uniqueID) {
			problems = append(problems, conftypes.NewSiteProblems(fmt.Sprintf(`Cannot have more than one GitLab auth provider with url %q and client ID %q, only the first one will be used`, provider.ServiceID, ci.ClientID))...)
			continue
		}

		ps = append(ps, Provider{
			GitLabAuthProvider: pr.Gitlab,
			Provider:           provider,
		})

		existingProviders.Add(uniqueID)
	}
	return ps, problems
}

