	"github.com/sourcegraph/sourcegraph/internal/gating"
	"github.com/sourcegraph/sourcegraph/lib/errors"
	"github.com/sourcegraph/sourcegraph/schema"
)

const sessionKey = "gitlaboauth@0"

var defaultGithubURL = schema.MustParseNormalizedURL("https://gitlab.com/").URL()

func parseProvider(logger log.Logger, gp gating.Provider, db database.DB, callbackURL string, p *schema.GitLabAuthProvider, sourceCfg schema.AuthProviders) *oauth.Provider {
	var URL *url.URL
	if p.Url == nil {
		URL = defaultGithubURL
	} else {
		URL = p.Url.URL()
	}
	codeHost := extsvc.NewCodeHost(URL, extsvc.TypeGitLab)

	return oauth.NewProvider(logger, db, oauth.ProviderOp{
		AuthPrefix: authPrefix,
		OAuth2Config: func() oauth2.Config {
			return oauth2.Config{
				RedirectURL:  callbackURL,
				ClientID:     p.ClientID,
				ClientSecret: p.ClientSecret,
				Scopes:       gitlab.RequestedOAuthScopes(p.ApiScope),
				Endpoint: oauth2.Endpoint{
					AuthURL:  codeHost.BaseURL.ResolveReference(&url.URL{Path: "/oauth/authorize"}).String(),
					TokenURL: codeHost.BaseURL.ResolveReference(&url.URL{Path: "/oauth/token"}).String(),
				},
			}
		},
		SourceConfig: sourceCfg,
		ServiceID:    codeHost.ServiceID,
		ServiceType:  codeHost.ServiceType,
		Login: func(oauth2Cfg oauth2.Config) http.Handler {
			// If p.SsoURL is set, we want to use our own SSOLoginHandler
			// that takes care of GitLab SSO sign-in redirects.
			if p.SsoURL != "" {
				return SSOLoginHandler(&oauth2Cfg, nil, p.SsoURL)
			}
			// Otherwise use the normal LoginHandler
			return LoginHandler(&oauth2Cfg, nil)
		},
		Callback: func(oauth2Cfg oauth2.Config) http.Handler {
			failureHandler := validationAwareFailureHandler(logger, db)

			return CallbackHandler(
				&oauth2Cfg,
				oauth.SessionIssuer(logger, gp, db, &sessionIssuerHelper{
					logger:      logger.Scoped("sessionIssuerHelper"),
					db:          db,
					CodeHost:    codeHost,
					clientID:    p.ClientID,
					allowSignup: p.AllowSignup,
					allowGroups: p.AllowGroups,
					scopes:      oauth2Cfg.Scopes,
				}, sessionKey),
				failureHandler,
			)
		},
	})
}

func validationAwareFailureHandler(logger log.Logger, _ database.DB) http.Handler {
	return http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
		ctx := r.Context()
		encodedState, err := goauth2.StateFromContext(ctx)
		if err != nil {
			logger.Error("OAuth failed: could not get state from context", log.Error(err))
			http.Error(w, "Authentication failed. Try signing in again.", http.StatusInternalServerError)
			return
		}
		state, err := oauth.DecodeState(encodedState)
		if err != nil {
			logger.Error("OAuth failed: could not decode state", log.Error(err))
			http.Error(w, "Authentication failed. Try signing in again.", http.StatusInternalServerError)
			return
		}
		oauthErr := r.URL.Query().Get("error")
		errorDesc := r.URL.Query().Get("error_description")
		validationID := state.ValidationID
		if validationID == "" {
			http.Error(w, "Authentication failed. Try signing in again.", http.StatusBadRequest)
			return
		}

		validationSession, err := authvalidation.GetRequiredValidationSession(ctx, authvalidation.ID(validationID))
		if err != nil {
			logger.Error("OAuth validation failure: session not found", log.Error(err))
			http.Error(w, "Validation session expired", http.StatusBadRequest)
			return
		}

		errMsg := "OAuth authentication failed"
		if oauthErr != "" {
			errMsg = fmt.Sprintf("OAuth error: %s", oauthErr)
		}
		if errorDesc != "" {
			errMsg = fmt.Sprintf("%s - %s", errMsg, errorDesc)
		}

		authvalidation.HandleValidationError(
			ctx,
			logger,
			w,
			r,
			validationSession,
			validationSession.ProviderType,
			errors.New(errMsg),
		)
	})
}

