package gitlaboauth

import (
	"context"
	"net/url"
	"reflect"
	"testing"

	"golang.org/x/oauth2"

	"github.com/sourcegraph/log/logtest"

	"github.com/sourcegraph/sourcegraph/cmd/frontend/auth"
	"github.com/sourcegraph/sourcegraph/internal/actor"
	"github.com/sourcegraph/sourcegraph/internal/database"
	"github.com/sourcegraph/sourcegraph/internal/database/dbmocks"
	"github.com/sourcegraph/sourcegraph/internal/extsvc"
	"github.com/sourcegraph/sourcegraph/internal/extsvc/gitlab"
	"github.com/sourcegraph/sourcegraph/lib/check"
	"github.com/sourcegraph/sourcegraph/lib/errors"
)

func TestSessionIssuerHelper_GetOrCreateUser(t *testing.T) {
	glURL, _ := url.Parse("https://gitlab.com")
	codeHost := extsvc.NewCodeHost(glURL, extsvc.TypeGitLab)
	clientID := "client-id"

	authSaveableUsers := map[string]int32{
		"alice": 1,
		"cindy": 3,
		"dan":   4,
	}

	signupNotAllowed := new(bool)
	signupAllowed := new(bool)
	*signupAllowed = true

	type input struct {
		description     string
		glUser          *gitlab.AuthUser
		glUserGroups    []*gitlab.Group
		glUserGroupsErr error
		allowSignup     *bool
		allowGroups     []string
		scopes          []string
	}

	cases := []struct {
		inputs        []input
		expActor      *actor.Actor
		expErr        bool
		expAuthUserOp *auth.GetAndSaveUserOp
	}{
		{
			inputs: []input{{
				description: "glUser, allowSignup not set, defaults to true -> new user and session created",
				glUser: &gitlab.AuthUser{
					ID:       int32(104),
					Username: "dan",
					Email:    "dan@example.com",
				},
				scopes: []string{"read_user", "api"},
			}},
			expActor: &actor.Actor{UID: 4},
			expAuthUserOp: &auth.GetAndSaveUserOp{
				UserProps: database.NewUser{
					Username:        "dan",
					Email:           "dan@example.com",
					EmailIsVerified: true,
				},
				ExternalAccount: extsvc.AccountSpec{
					ServiceType: extsvc.TypeGitLab,
					ServiceID:   "https://gitlab.com/",
					ClientID:    clientID,
					AccountID:   "104",
				},
				CreateIfNotExist: true,
			},
		},
		{
			inputs: []input{{
				description: "glUser, allowSignup set to false -> no new user nor session created",
				allowSignup: signupNotAllowed,
				glUser: &gitlab.AuthUser{
					ID:       int32(102),
					Username: "bob",
					Email:    "bob@example.com",
				},
			}},
			expErr: true,
		},
		{
			inputs: []input{{
				description: "glUser, allowSignup set to false, allowedGroups list provided -> no new user nor session created",
				allowSignup: signupNotAllowed,
				allowGroups: []string{"group1"},
				glUser: &gitlab.AuthUser{
					ID:       int32(102),
					Username: "bob",
					Email:    "bob@example.com",
				},
				glUserGroups: []*gitlab.Group{
					{FullPath: "group1"},
				},
			}},
			expErr: true,
		},
		{
			inputs: []input{{
				description: "glUser, allowSignup set true -> new user and session created",
				allowSignup: signupAllowed,
				glUser: &gitlab.AuthUser{
					ID:       int32(103),
					Username: "cindy",
					Email:    "cindy@example.com",
				},
				scopes: []string{"read_user"},
			}},
			expActor: &actor.Actor{UID: 3},
			expAuthUserOp: &auth.GetAndSaveUserOp{
				UserProps: database.NewUser{
					Username:        "cindy",
					Email:           "cindy@example.com",
					EmailIsVerified: true,
				},
				ExternalAccount: extsvc.AccountSpec{
					ServiceType: extsvc.TypeGitLab,
					ServiceID:   "https://gitlab.com/",
					ClientID:    clientID,
					AccountID:   "101",
				},
				CreateIfNotExist: true,
			},
		},
		{
			inputs: []input{{
				description: "glUser, allowedGroups not set -> session created",
				glUser: &gitlab.AuthUser{
					ID:       int32(101),
					Username: "alice",
					Email:    "alice@example.com",
				},
				scopes: []string{"read_user", "api"},
			}},
			expActor: &actor.Actor{UID: 1},
			expAuthUserOp: &auth.GetAndSaveUserOp{
				UserProps: database.NewUser{
					Username:        "alice",
					Email:           "alice@example.com",
					EmailIsVerified: true,
				},
				ExternalAccount: extsvc.AccountSpec{
					ServiceType: extsvc.TypeGitLab,
					ServiceID:   "https://gitlab.com/",
					ClientID:    clientID,
					AccountID:   "101",
				},
				CreateIfNotExist: true,
			},
		},
		{
			inputs: []input{{
				description: "glUser, not in allowed groups -> no session created",
				allowGroups: []string{"group2"},
				glUser: &gitlab.AuthUser{
					ID:       int32(101),
					Username: "alice",
					Email:    "alice@example.com",
				},
				glUserGroups: []*gitlab.Group{
					{FullPath: "group1"},
				},
			}},
			expErr: true,
		},
		{
			inputs: []input{{
				description: "glUser, in allowed groups, error getting user groups -> no session created",
				allowGroups: []string{"group1"},
				glUser: &gitlab.AuthUser{
					ID:       int32(101),
					Username: "alice",
					Email:    "alice@example.com",
				},
				glUserGroups: []*gitlab.Group{
					{FullPath: "group1"},
					{FullPath: "group2"},
				},
				glUserGroupsErr: errors.New("boom"),
			}},
			expErr: true,
		},
		{
			inputs: []input{{
				description: "glUser, in allowed groups -> session created",
				allowGroups: []string{"group1"},
				glUser: &gitlab.AuthUser{
					ID:       int32(101),
					Username: "alice",
					Email:    "alice@example.com",
				},
				glUserGroups: []*gitlab.Group{
					{FullPath: "group1"},
					{FullPath: "group2"},
				},
				scopes: []string{"read_user", "read_api"},
			}},
			expActor: &actor.Actor{UID: 1},
			expAuthUserOp: &auth.GetAndSaveUserOp{
				UserProps: database.NewUser{
					Username:        "alice",
					Email:           "alice@example.com",
					EmailIsVerified: true,
				},
				ExternalAccount: extsvc.AccountSpec{
					ServiceType: extsvc.TypeGitLab,
					ServiceID:   "https://gitlab.com/",
					ClientID:    clientID,
					AccountID:   "101",
				},
				CreateIfNotExist: true,
			},
		},
		{
			inputs: []input{{
				description: "glUser, not in allowed subgroup -> session not created",
				allowGroups: []string{"group1/subgroup1"},
				glUser: &gitlab.AuthUser{
					ID:       int32(101),
					Username: "alice",
					Email:    "alice@example.com",
				},
				glUserGroups: []*gitlab.Group{
					{FullPath: "group1/subgroup2"},
				},
			}},
			expErr: true,
		},
		{
			inputs: []input{{
				description: "glUser, in allowed subgroup  -> session created",
				allowGroups: []string{"group1/subgroup2"},
				glUser: &gitlab.AuthUser{
					ID:       int32(101),
					Username: "alice",
					Email:    "alice@example.com",
				},
				glUserGroups: []*gitlab.Group{
					{FullPath: "group1/subgroup2"},
				},
				scopes: []string{"read_user"},
			}},
			expActor: &actor.Actor{UID: 1},
			expAuthUserOp: &auth.GetAndSaveUserOp{
				UserProps: database.NewUser{
					Username:        "alice",
					Email:           "alice@example.com",
					EmailIsVerified: true,
				},
				ExternalAccount: extsvc.AccountSpec{
					ServiceType: extsvc.TypeGitLab,
					ServiceID:   "https://gitlab.com/",
					ClientID:    clientID,
					AccountID:   "101",
				},
				CreateIfNotExist: true,
			},
		},
	}

	for _, c := range cases {
		for _, ci := range c.inputs {
			c, ci := c, ci

			t.Run(ci.description, func(t *testing.T) {

				// Build a set of group full paths from the test input to simulate
				// the targeted membership check used by IsGroupMember.
				memberGroups := make(map[string]bool)
				for _, g := range ci.glUserGroups {
					memberGroups[g.FullPath] = true
				}
				gitlab.MockIsGroupMember = func(ctx context.Context, groupPath string, userID int32) (bool, error) {
					if ci.glUserGroupsErr != nil {
						return false, ci.glUserGroupsErr
					}
					return memberGroups[groupPath], nil
				}

				var gotAuthUserOp *auth.GetAndSaveUserOp
				getAndSaveUserError := errors.New("auth.GetAndSaveUser error")

				auth.MockGetAndSaveUser = func(ctx context.Context, op auth.GetAndSaveUserOp) (result *auth.GetAndSaveUserResult, safeErrMsg string, err error) {
					if gotAuthUserOp != nil {
						t.Fatal("GetAndSaveUser called more than once")
					}

					op.ExternalAccountData = extsvc.AccountData{}
					gotAuthUserOp = &op

					if uid, ok := authSaveableUsers[op.UserProps.Username]; ok {
						return &auth.GetAndSaveUserResult{NewUserCreated: false, UserID: uid}, "", nil
					}

					return nil, "safeErr", getAndSaveUserError
				}

				defer func() {
					auth.MockGetAndSaveUser = nil
					gitlab.MockIsGroupMember = nil
				}()

				ctx := WithUser(context.Background(), ci.glUser)

				extAcctStore := dbmocks.NewMockUserExternalAccountsStore()
				extAcctStore.GetByServiceFunc.SetDefaultReturn(nil, errors.New("not found"))
				db := dbmocks.NewMockDB()
				db.UserExternalAccountsFunc.SetDefaultReturn(extAcctStore)

				s := &sessionIssuerHelper{
					logger:      logtest.Scoped(t),
					db:          db,
					CodeHost:    codeHost,
					clientID:    clientID,
					allowSignup: ci.allowSignup,
					allowGroups: ci.allowGroups,
					scopes:      ci.scopes,
				}

				tok := &oauth2.Token{AccessToken: "dummy-value-that-isnt-relevant-to-unit-correctness"}
				result, _, err := s.GetOrCreateUser(ctx, tok)

				var actr *actor.Actor
				if result != nil {
					actr = result.Actor
				}
				if got, exp := actr, c.expActor; !reflect.DeepEqual(got, exp) {
					t.Errorf("expected actor %v, got %v", exp, got)
				}

				if c.expErr && err == nil {
					t.Errorf("expected err %v, but was nil", c.expErr)
				} else if !c.expErr && err != nil {
					t.Errorf("expected no error, but was %v", err)
				}

				if c.expErr && err != getAndSaveUserError {
					check.NoDiff(t, c.expAuthUserOp, gotAuthUserOp, "auth user op")
				}
			})
		}
	}
}

