	check.MustNoError(t, err)
	confStore.GetExternalURLFunc.SetDefaultReturn(u, nil)

	db.ConfFunc.SetDefaultReturn(confStore)

	gitlabURL := schema.MustParseNormalizedURL("https://gitlab.com")
	companyURL := schema.MustParseNormalizedURL("https://mycompany.com")

	type args struct {
		cfg *conf.Unified
	}
	tests := []struct {
		name          string
