package gitlab

import (
	"context"
	"fmt"
	"net/http"
	"net/url"
	"strconv"
	"strings"

	"github.com/sourcegraph/sourcegraph/internal/extsvc/gitlab/gql"
	"github.com/sourcegraph/sourcegraph/lib/collections"
	"github.com/sourcegraph/sourcegraph/lib/errors"
)

type Group struct {
	ID          int32  `json:"id"`
	Name        string `json:"name"`
	FullPath    string `json:"full_path"`
	Description string `json:"description"`
	WebURL      string `json:"web_url"`
	AvatarURL   string `json:"avatar_url"`
	Visibility  string `json:"visibility"`
}

var (
	MockIsGroupMember  func(ctx context.Context, groupPath string, userID int32) (bool, error)
	MockGetGroupsByIDs func(c *Client, ctx context.Context, ids []string) ([]*Group, error)
)

// IsGroupMember checks whether a user is a member of a GitLab group (including inherited membership)
func (c *Client) IsGroupMember(ctx context.Context, groupPath string, userID int32) (bool, error) {
	if MockIsGroupMember != nil {
		return MockIsGroupMember(ctx, groupPath, userID)
	}

	u := fmt.Sprintf("groups/%s/members/all/%d", url.PathEscape(groupPath), userID)
	req, err := http.NewRequestWithContext(ctx, "GET", u, nil)
	if err != nil {
		return false, err
	}

	var member struct{}
	_, _, err = c.do(ctx, req, &member)
	if err != nil {
		if IsNotFound(err) {
			return false, nil
		}
		return false, err
	}

	return true, nil
}

// ListTopLevelUserGroups lists the top-most groups that the current authenticated user is a member of.
// If a user is only a member of a sub-group, this method will return the top-most group that contains that sub-group.
// It supports search, pagination, and returns total count for UI purposes.
//
// Note: When calling subsequent pages, call the same method with the same arguments, just
// with the previous "after" value. (Any changes to the other arguments like "limit" will result in undefined behavior.)
func (c *Client) ListTopLevelUserGroups(ctx context.Context, search string, limit int, after string) ([]*Group, int, string, error) {
	if MockListTopLevelUserGroups != nil {
		return MockListTopLevelUserGroups(c, ctx, search, limit, after)
	}

	if limit <= 0 || limit > 100 {
		return nil, 0, "", errors.New("limit must be between 1 and 100")
	}

	graphqlClient := c.mkGraphQLClient()
	response, err := graphqlClient.GetTopLevelUserGroups(ctx, limit, after, search)
	if err != nil {
		return nil, 0, "", errors.Wrap(err, "failed to fetch user groups via GraphQL")
	}

	groupsConnection := response.GetGroups()
	nodes := groupsConnection.GetNodes()

	groups := make([]*Group, 0, len(nodes))
	for _, gqlGroup := range nodes {
		group, err := convertGraphQLGroupToGroup(&gqlGroup)
		if err != nil {
			return nil, 0, "", errors.Wrapf(err, "failed to convert GraphQL group %s", gqlGroup.GetId())
		}
		groups = append(groups, group)
	}

	totalCount := groupsConnection.GetCount()
	pageInfo := groupsConnection.GetPageInfo()

	nextCursor := ""
	if pageInfo.GetHasNextPage() {
		nextCursor = pageInfo.GetEndCursor()
	}

	return groups, totalCount, nextCursor, nil
}

// GetGroup retrieves detailed information about a specific group.
func (c *Client) GetGroup(ctx context.Context, id int) (*Group, error) {
	if MockGetGroup != nil {
		return MockGetGroup(c, ctx, id)
	}

	req, err := http.NewRequestWithContext(ctx, "GET", fmt.Sprintf("groups/%d", id), nil)
	if err != nil {
		return nil, err
	}

	var group Group
	_, _, err = c.do(ctx, req, &group)
	if err != nil {
		return nil, err
	}

	return &group, nil
}

// GetGroupsByIDs retrieves multiple groups by their IDs using the GitLab GraphQL API.
// This method supports batch fetching up to 50 groups at a time to align with GitLab API limits.
// Group IDs should be provided as GraphQL Global IDs (e.g., "gid://gitlab/Group/1234") or
// numeric strings that will be converted to GraphQL Global IDs automatically.
//
// The method handles internal pagination transparently - if GitLab paginates the response,
// this method will make additional requests to fetch all requested groups.
//
// Returns:
//   - groups: slice of Group objects for the requested IDs
//   - error: any error encountered during the API call
//
// Example usage:
//
//	groups, err := client.GetGroupsByIDs(ctx, []string{"gid://gitlab/Group/1234", "5678"})
func (c *Client) GetGroupsByIDs(ctx context.Context, ids []string) ([]*Group, error) {
	if MockGetGroupsByIDs != nil {
		return MockGetGroupsByIDs(c, ctx, ids)
	}

	if len(ids) == 0 {
		return []*Group{}, nil
	}

	if len(ids) > 50 {
		return nil, errors.New("cannot fetch more than 50 groups at once")
	}

	// Convert numeric IDs to GraphQL Global IDs if needed
	gqlIDs := make([]string, len(ids))
	for i, id := range ids {
		if isNumericID(id) {
			gqlIDs[i] = fmt.Sprintf("gid://gitlab/Group/%s", id)
		} else {
			gqlIDs[i] = id
		}
	}

	deduplicatedIDs := collections.Deduplicate(gqlIDs)

	graphqlClient := c.mkGraphQLClient()
	allGroups := make([]*Group, 0, len(deduplicatedIDs))
	cursor := ""

	for {
		// Request a reasonable page size to avoid too many API calls
		// Since we're limited to 50 total groups, use 50 as first value
		response, err := graphqlClient.GetGroupsByIDs(ctx, deduplicatedIDs, 50, cursor)
		if err != nil {
			return nil, errors.Wrap(err, "failed to fetch groups via GraphQL")
		}

		groups := response.GetGroups()
		nodes := groups.GetNodes()

		// Convert and append this page of groups
